targets.rawSql:
SELECT count(DISTINCT h.target_name)::bigint AS targets
FROM monitoring.db_port_blackbox_hourly_kpi h
WHERE $__timeFilter(h.period_hour) AND ('$environment' = '%' OR h.environment = '$environment') AND ('$db_type' = '%' OR h.db_type = '$db_type') AND ('$target' = '%' OR h.target_name = '$target') AND ('$criticality' = '%' OR coalesce(h.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(h.team, 'unassigned') = '$team');

SELECT coalesce(sum(h.down_probes), 0)::bigint AS down_target_minutes
FROM monitoring.db_port_blackbox_hourly_kpi h
WHERE $__timeFilter(h.period_hour) AND ('$environment' = '%' OR h.environment = '$environment') AND ('$db_type' = '%' OR h.db_type = '$db_type') AND ('$target' = '%' OR h.target_name = '$target') AND ('$criticality' = '%' OR coalesce(h.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(h.team, 'unassigned') = '$team');

SELECT count(*)::bigint AS incidents_started
FROM monitoring.db_port_blackbox_downtime_events e
WHERE $__timeFilter(e.down_start) AND ('$environment' = '%' OR e.environment = '$environment') AND ('$db_type' = '%' OR e.db_type = '$db_type') AND ('$target' = '%' OR e.target_name = '$target') AND ('$criticality' = '%' OR coalesce(e.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(e.team, 'unassigned') = '$team');

SELECT coalesce(round(avg(extract(epoch FROM e.down_end - e.down_start) / 60.0)::numeric, 2), 0) AS mttr_minutes
FROM monitoring.db_port_blackbox_downtime_events e
WHERE $__timeFilter(e.down_start) AND e.down_end IS NOT NULL AND ('$environment' = '%' OR e.environment = '$environment') AND ('$db_type' = '%' OR e.db_type = '$db_type') AND ('$target' = '%' OR e.target_name = '$target') AND ('$criticality' = '%' OR coalesce(e.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(e.team, 'unassigned') = '$team');

SELECT coalesce(round(sum(h.latency_ms_sum) / nullif(sum(h.latency_ms_count), 0), 2), 0) AS avg_latency_ms
FROM monitoring.db_port_blackbox_hourly_kpi h
WHERE $__timeFilter(h.period_hour) AND ('$environment' = '%' OR h.environment = '$environment') AND ('$db_type' = '%' OR h.db_type = '$db_type') AND ('$target' = '%' OR h.target_name = '$target') AND ('$criticality' = '%' OR coalesce(h.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(h.team, 'unassigned') = '$team');
